#include<bits/stdc++.h>
using namespace std;
struct fs{
	long long fz,fm;
};
fs yf(fs a){
    long long gcd=__gcd(a.fm,a.fz);
    a.fm/=gcd,a.fz/=gcd;
    return a;
}
fs jia(fs x,fs y){
    x.fz=x.fz*y.fm+y.fz*x.fm;
    x.fm=x.fm*y.fm;
    return yf(x);
}
fs jian(fs x,fs y){
    x.fz=x.fz*y.fm-y.fz*x.fm;
    x.fm=x.fm*y.fm;
    return yf(x);
}
int main(void){
	fs a,b;
    char fh;
    scanf("%lld/%lld",&a.fz,&a.fm);
    a=yf(a);
    cin>>fh;
    while (scanf("%lld/%lld",&b.fz,&b.fm)!=EOF){
        if(fh==EOF)break;
        else if(fh=='+')a=jia(a,b);
        else if(fh=='-')a=jian(a,b);
        cin>>fh;
    }
    if(a.fm<0&&a.fz>0)a.fm=abs(a.fm),a.fz-=a.fz*2;
    if(a.fm==1)cout<<a.fz;
    else cout<<a.fz<<'/'<<a.fm;
    return false;
}
